import pytest
import torch
import torch.nn as nn
import sys, os
sys.path.insert(0, os.path.join(os.path.dirname(__file__), '..'))

def make_simple_model(D):
    return nn.Sequential(nn.Linear(D, D*2), nn.ReLU(), nn.Linear(D*2, 1))

def run_steps(model, opt, n_steps=10, D=16):
    losses = []
    for _ in range(n_steps):
        x = torch.randn(8, D)
        y = torch.randn(8, 1)
        loss = nn.functional.mse_loss(model(x), y)
        opt.zero_grad()
        loss.backward()
        opt.step()
        losses.append(loss.item())
    return losses

