def test_adam_converges(D, lr, b1, b2, eps, wd, seed):
    torch.manual_seed(seed)
    model = make_simple_model(D)
    opt = torch.optim.Adam(model.parameters(), lr=lr, betas=(b1,b2), eps=eps, weight_decay=wd)
    losses = run_steps(model, opt, n_steps=5, D=D)
