def test_sgd_runs(D, lr, momentum, wd, nesterov, seed):
    torch.manual_seed(seed)
    if nesterov and momentum == 0.0:
        pytest.skip('Nesterov requires momentum>0')
    model = make_simple_model(D)
    opt = torch.optim.SGD(model.parameters(), lr=lr, momentum=momentum, weight_decay=wd, nesterov=nesterov)
    losses = run_steps(model, opt, n_steps=5, D=D)
